import {
  type KeyboardEvent,
  type ReactElement,
  useCallback,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";

import { type AccessibleText } from "../../lib/a11y-types";
import { withErrorOverlay } from "../../lib/dev-overlay";

// ---------------------------------------------------------------------------
// Label prop — exactly one source required; combinations are compile errors
// ---------------------------------------------------------------------------

type DatepickerLabelProps =
  | { label: AccessibleText; "aria-label"?: never; "aria-labelledby"?: never }
  | { label?: never; "aria-label": AccessibleText; "aria-labelledby"?: never }
  | { label?: never; "aria-label"?: never; "aria-labelledby": string };

type DatepickerBaseProps = {
  value: Date | null;
  onChange: (next: Date | null) => void;
  /** BCP-47 locale tag. Defaults to navigator.language. */
  locale?: string;
  min?: Date;
  max?: Date;
  isDateDisabled?: (date: Date) => boolean;
  /** External validation error shown below the input and wired via aria-describedby. */
  error?: string;
  required?: boolean;
};

export type DatepickerProps = DatepickerBaseProps & DatepickerLabelProps;

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function isSameDay(a: Date, b: Date): boolean {
  return (
    a.getFullYear() === b.getFullYear() &&
    a.getMonth() === b.getMonth() &&
    a.getDate() === b.getDate()
  );
}

function startOfMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth(), 1);
}

function endOfMonth(d: Date): Date {
  return new Date(d.getFullYear(), d.getMonth() + 1, 0);
}

function addDays(d: Date, n: number): Date {
  const next = new Date(d);
  next.setDate(next.getDate() + n);
  return next;
}

function addMonths(d: Date, n: number): Date {
  const next = new Date(d);
  const targetMonth = next.getMonth() + n;
  next.setMonth(targetMonth);
  // Clamp to the last day of the new month when the day overflows
  // (e.g. Jan 31 + 1 month → Feb 28, not Mar 2).
  if (next.getMonth() !== ((targetMonth % 12) + 12) % 12) {
    next.setDate(0);
  }
  return next;
}

function clampToMonth(d: Date, month: Date): Date {
  const first = startOfMonth(month);
  const last = endOfMonth(month);
  if (d < first) return first;
  if (d > last) return last;
  return d;
}

/** Week start day: 0=Sunday, 1=Monday. Falls back to Monday for locales without Intl.Locale.getWeekInfo. */
function getWeekStartDay(locale: string): 0 | 1 {
  try {
    const info = (new Intl.Locale(locale) as { getWeekInfo?: () => { firstDay?: number } }).getWeekInfo?.();
    if (info && info.firstDay === 7) return 0; // Sunday
    return 1; // Monday for most of the world including nl-BE
  } catch {
    return 1;
  }
}

/** Locale-aware input format hint: returns "DD/MM/YYYY", "MM/DD/YYYY", or "YYYY-MM-DD". */
function getDateFormat(locale: string): string {
  const parts = new Intl.DateTimeFormat(locale, {
    day: "2-digit",
    month: "2-digit",
    year: "numeric",
  }).formatToParts(new Date(2026, 0, 31));

  const order = parts
    .filter((p) => p.type === "day" || p.type === "month" || p.type === "year")
    .map((p) => p.type);

  if (order[0] === "year") return "YYYY-MM-DD";
  if (order[0] === "month") return "MM/DD/YYYY";
  return "DD/MM/YYYY";
}

/** Parse a user-typed string according to the locale format. Returns Date or null. */
function parseInputValue(raw: string, locale: string): Date | null {
  const trimmed = raw.trim();
  if (!trimmed) return null;

  const fmt = getDateFormat(locale);
  let year: number, month: number, day: number;

  const parts = trimmed.split(/[-/]/).map(Number);
  if (fmt === "YYYY-MM-DD") {
    year = parts[0] ?? NaN;
    month = parts[1] ?? NaN;
    day = parts[2] ?? NaN;
  } else if (fmt === "MM/DD/YYYY") {
    month = parts[0] ?? NaN;
    day = parts[1] ?? NaN;
    year = parts[2] ?? NaN;
  } else {
    // DD/MM/YYYY
    day = parts[0] ?? NaN;
    month = parts[1] ?? NaN;
    year = parts[2] ?? NaN;
  }

  if (!year || !month || !day || isNaN(year) || isNaN(month) || isNaN(day))
    return null;
  if (month < 1 || month > 12) return null;
  const date = new Date(year, month - 1, day);
  if (
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  )
    return null;

  return date;
}

/** Format a Date for display in the text input. */
function formatDateForInput(date: Date, locale: string): string {
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, "0");
  const d = String(date.getDate()).padStart(2, "0");
  const fmt = getDateFormat(locale);
  if (fmt === "YYYY-MM-DD") return `${y}-${m}-${d}`;
  if (fmt === "MM/DD/YYYY") return `${m}/${d}/${y}`;
  return `${d}/${m}/${y}`;
}

/** Build a 6-row × 7-col grid of dates for the calendar, padded to fill weeks. */
function buildCalendarGrid(month: Date, weekStart: 0 | 1): (Date | null)[][] {
  const first = startOfMonth(month);
  const last = endOfMonth(month);

  // Day of week for the first of the month (adjusted for week start)
  const startOffset = (first.getDay() - weekStart + 7) % 7;

  const cells: (Date | null)[] = [];
  for (let i = 0; i < startOffset; i++) cells.push(null);

  for (let d = 1; d <= last.getDate(); d++) {
    cells.push(new Date(month.getFullYear(), month.getMonth(), d));
  }

  // Pad to a multiple of 7
  while (cells.length % 7 !== 0) cells.push(null);

  const rows: (Date | null)[][] = [];
  for (let i = 0; i < cells.length; i += 7) {
    rows.push(cells.slice(i, i + 7));
  }
  return rows;
}

/** Validate a BCP-47 locale string. Returns true if valid. */
function isValidLocale(locale: string): boolean {
  try {
    new Intl.Locale(locale);
    return true;
  } catch {
    return false;
  }
}

// ---------------------------------------------------------------------------
// CSS (injected once as a <style> element)
// ---------------------------------------------------------------------------

const STYLE = `
.artui-datepicker {
  display: inline-flex;
  flex-direction: column;
  gap: 4px;
  position: relative;
  font-family: inherit;
  font-size: inherit;
}

.artui-dp-label {
  font-size: 0.875em;
  font-weight: 500;
  color: inherit;
}

.artui-dp-input-row {
  display: flex;
  gap: 0;
  align-items: stretch;
}

.artui-dp-input {
  flex: 1;
  min-width: 0;
  padding: 8px 12px;
  border: 1px solid currentColor;
  border-right: none;
  border-radius: 4px 0 0 4px;
  font-family: inherit;
  font-size: inherit;
  background: transparent;
  color: inherit;
  outline: none;
}
.artui-dp-input:focus {
  outline: var(--artui-dp-focus-outline, 2px solid currentColor);
  outline-offset: var(--artui-dp-focus-outline-offset, 2px);
}

.artui-dp-trigger {
  min-width: 44px;
  min-height: 44px;
  padding: 0 12px;
  border: 1px solid currentColor;
  border-radius: 0 4px 4px 0;
  background: transparent;
  color: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1.1em;
}
.artui-dp-trigger:focus {
  outline: var(--artui-dp-focus-outline, 2px solid currentColor);
  outline-offset: var(--artui-dp-focus-outline-offset, 2px);
}

.artui-dp-error {
  font-size: 0.8em;
  color: #c0392b;
  min-height: 1.2em;
}

.artui-dp-dialog {
  position: absolute;
  top: calc(100% + 4px);
  left: 0;
  z-index: 100;
  background: var(--artui-dp-dialog-bg, #ffffff);
  color: var(--artui-dp-dialog-color, #1a1a1a);
  box-shadow: var(--artui-dp-dialog-shadow, 0 4px 24px rgba(0,0,0,0.18));
  border-radius: 6px;
  padding: 12px;
  min-width: 280px;
}

.artui-dp-dialog-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 8px;
  gap: 4px;
}

.artui-dp-nav-btn {
  min-width: 44px;
  min-height: 44px;
  padding: 0 8px;
  border: 1px solid transparent;
  border-radius: 4px;
  background: transparent;
  color: inherit;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  font-size: 1em;
}
.artui-dp-nav-btn:focus {
  outline: var(--artui-dp-focus-outline, 2px solid currentColor);
  outline-offset: var(--artui-dp-focus-outline-offset, 2px);
}
.artui-dp-nav-btn:hover {
  background: rgba(0,0,0,0.06);
}

.artui-dp-heading {
  flex: 1;
  text-align: center;
  font-size: 1em;
  font-weight: 600;
  margin: 0;
}

.artui-dp-close-btn {
  min-width: 44px;
  min-height: 44px;
  padding: 0 8px;
  border: 1px solid transparent;
  border-radius: 4px;
  background: transparent;
  color: inherit;
  cursor: pointer;
  font-size: 1em;
  display: flex;
  align-items: center;
  justify-content: center;
}
.artui-dp-close-btn:focus {
  outline: var(--artui-dp-focus-outline, 2px solid currentColor);
  outline-offset: var(--artui-dp-focus-outline-offset, 2px);
}

.artui-dp-grid {
  border-collapse: collapse;
  width: 100%;
  table-layout: fixed;
}

.artui-dp-grid th {
  font-size: 0.75em;
  font-weight: 600;
  text-align: center;
  padding: 4px 0;
  color: inherit;
  opacity: 0.6;
}

.artui-dp-day-cell {
  padding: 2px;
  text-align: center;
}

.artui-dp-day-btn {
  width: var(--artui-dp-cell-size, 44px);
  height: var(--artui-dp-cell-size, 44px);
  border: none;
  border-radius: 50%;
  background: transparent;
  color: inherit;
  cursor: pointer;
  font-family: inherit;
  font-size: 0.875em;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  transition: background var(--artui-dp-transition-duration, 150ms) var(--artui-dp-transition-easing, ease-out);
}
.artui-dp-day-btn:focus {
  outline: var(--artui-dp-focus-outline, 2px solid currentColor);
  outline-offset: var(--artui-dp-focus-outline-offset, 2px);
}
.artui-dp-day-btn:hover:not(:disabled) {
  background: rgba(0,0,0,0.08);
}
.artui-dp-day-btn[aria-selected="true"] {
  background: var(--artui-dp-selected-bg, #0057b7);
  color: var(--artui-dp-selected-color, #ffffff);
}
.artui-dp-day-btn[aria-current="date"]:not([aria-selected="true"]) {
  outline: var(--artui-dp-today-outline, 2px solid currentColor);
  outline-offset: var(--artui-dp-focus-outline-offset, 2px);
}
.artui-dp-day-btn:disabled,
.artui-dp-day-btn[aria-disabled="true"] {
  opacity: var(--artui-dp-disabled-opacity, 0.4);
  cursor: not-allowed;
  pointer-events: none;
}

.artui-dp-empty-cell {
  /* padding cell for days outside the current month */
}

.artui-dp-sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  padding: 0;
  margin: -1px;
  overflow: hidden;
  clip: rect(0,0,0,0);
  white-space: nowrap;
  border: 0;
}

@media (prefers-reduced-motion: reduce) {
  .artui-dp-day-btn {
    transition: none;
    /* opacity-only fallback — no translate or scale animations */
  }
  .artui-dp-dialog {
    animation: none;
  }
}
`;

let styleInjected = false;

function injectStyle(): void {
  if (styleInjected || typeof document === "undefined") return;
  styleInjected = true;
  const el = document.createElement("style");
  el.dataset["artuiDp"] = "";
  el.textContent = STYLE;
  document.head.appendChild(el);
}

// ---------------------------------------------------------------------------
// Main component
// ---------------------------------------------------------------------------

export function Datepicker(props: DatepickerProps): ReactElement {
  const {
    value,
    onChange,
    locale: localeProp,
    min,
    max,
    isDateDisabled,
    error: externalError,
    required,
    ...labelRest
  } = props;

  // Resolve locale — fall back to navigator.language (or 'en' in SSR)
  const resolvedLocale = useMemo(() => {
    const candidate =
      localeProp ??
      (typeof navigator !== "undefined" ? navigator.language : "en");
    return isValidLocale(candidate) ? candidate : "en";
  }, [localeProp]);

  const weekStart = useMemo(
    () => getWeekStartDay(resolvedLocale),
    [resolvedLocale],
  );

  // IDs for ARIA wiring
  const uid = useId();
  const inputId = `${uid}-input`;
  const errorId = `${uid}-error`;
  const headingId = `${uid}-heading`;
  const liveRegionId = `${uid}-live`;

  // Refs
  const triggerRef = useRef<HTMLButtonElement>(null);
  const dialogRef = useRef<HTMLDivElement>(null);

  // State
  const [isOpen, setIsOpen] = useState(false);
  const [inputValue, setInputValue] = useState(() =>
    value ? formatDateForInput(value, resolvedLocale) : "",
  );
  const [inputError, setInputError] = useState<string | null>(null);
  const [displayMonth, setDisplayMonth] = useState<Date>(() =>
    value ? startOfMonth(value) : startOfMonth(new Date()),
  );
  const [focusedDate, setFocusedDate] = useState<Date>(
    () => value ?? new Date(),
  );
  const [liveText, setLiveText] = useState("");

  // Sync input display when value changes externally
  useEffect(() => {
    setInputValue(value ? formatDateForInput(value, resolvedLocale) : "");
  }, [value, resolvedLocale]);

  // ---------------------------------------------------------------------------
  // Runtime violation detection
  // ---------------------------------------------------------------------------

  const runtimeViolation = useMemo((): {
    key: string;
    wcag?: string;
    message: string;
  } | null => {
    // Invalid locale check
    if (localeProp && !isValidLocale(localeProp)) {
      return {
        key: `Datepicker:invalid-locale:${localeProp}`,
        message: `locale '${localeProp}' is not a valid BCP-47 tag. Falling back to navigator.language.`,
      };
    }
    if (min && max && min > max) {
      return {
        key: `Datepicker:min-gt-max:${min.toISOString()}:${max.toISOString()}`,
        wcag: "1.3.5",
        message: `min (${min.toISOString()}) is after max (${max.toISOString()}). The calendar cannot render a valid range.`,
      };
    }
    if (value) {
      if (min && value < min) {
        return {
          key: `Datepicker:value-out-of-range:${value.toISOString()}`,
          wcag: "1.3.5",
          message: `value (${value.toISOString()}) is before min (${min.toISOString()}).`,
        };
      }
      if (max && value > max) {
        return {
          key: `Datepicker:value-out-of-range:${value.toISOString()}`,
          wcag: "1.3.5",
          message: `value (${value.toISOString()}) is after max (${max.toISOString()}).`,
        };
      }
      if (isDateDisabled?.(value)) {
        return {
          key: `Datepicker:disabled-value:${value.toISOString()}`,
          message: `The current value (${value.toISOString()}) is disabled by isDateDisabled. The user cannot reach a selected state from the current UI.`,
        };
      }
    }
    return null;
  }, [localeProp, min, max, value, isDateDisabled]);

  // ---------------------------------------------------------------------------
  // Calendar helpers
  // ---------------------------------------------------------------------------

  const calendarGrid = useMemo(
    () => buildCalendarGrid(displayMonth, weekStart),
    [displayMonth, weekStart],
  );

  const headingText = useMemo(
    () =>
      new Intl.DateTimeFormat(resolvedLocale, {
        month: "long",
        year: "numeric",
      }).format(displayMonth),
    [displayMonth, resolvedLocale],
  );

  const isCellDisabled = useCallback(
    (date: Date): boolean => {
      if (min && date < startOfDay(min)) return true;
      if (max && date > startOfDay(max)) return true;
      if (isDateDisabled?.(date)) return true;
      return false;
    },
    [min, max, isDateDisabled],
  );

  function startOfDay(d: Date): Date {
    return new Date(d.getFullYear(), d.getMonth(), d.getDate());
  }

  const prevMonthLabel = useMemo(() => {
    const prev = addMonths(displayMonth, -1);
    return `Previous month, ${new Intl.DateTimeFormat(resolvedLocale, { month: "long", year: "numeric" }).format(prev)}`;
  }, [displayMonth, resolvedLocale]);

  const nextMonthLabel = useMemo(() => {
    const next = addMonths(displayMonth, 1);
    return `Next month, ${new Intl.DateTimeFormat(resolvedLocale, { month: "long", year: "numeric" }).format(next)}`;
  }, [displayMonth, resolvedLocale]);

  // Weekday column headers
  const weekdayHeaders = useMemo(() => {
    const headers = [];
    for (let i = 0; i < 7; i++) {
      const dayIndex = (weekStart + i) % 7;
      const date = new Date(2026, 0, 4 + dayIndex); // Jan 4 2026 is a Sunday (0)
      const short = new Intl.DateTimeFormat(resolvedLocale, {
        weekday: "short",
      }).format(date);
      const long = new Intl.DateTimeFormat(resolvedLocale, {
        weekday: "long",
      }).format(date);
      headers.push({ short, long });
    }
    return headers;
  }, [weekStart, resolvedLocale]);

  // ---------------------------------------------------------------------------
  // Open / close
  // ---------------------------------------------------------------------------

  function open(): void {
    const initial = value ?? new Date();
    setDisplayMonth(startOfMonth(initial));
    setFocusedDate(initial);
    setIsOpen(true);
  }

  function close(): void {
    setIsOpen(false);
  }

  // Focus management: on open, focus the active day cell; on focusedDate change while open,
  // move focus to the new active cell; on close, return focus to the trigger.
  useEffect(() => {
    if (isOpen) {
      dialogRef.current
        ?.querySelector<HTMLElement>('[data-focused-day="true"]')
        ?.focus();
    } else {
      triggerRef.current?.focus();
    }
  }, [isOpen, focusedDate]);

  // Update live region on month change
  useEffect(() => {
    if (isOpen) {
      setLiveText(headingText);
    }
  }, [headingText, isOpen]);

  // ---------------------------------------------------------------------------
  // Input handlers
  // ---------------------------------------------------------------------------

  function handleInputChange(raw: string): void {
    setInputValue(raw);
    const fmt = getDateFormat(resolvedLocale);
    const parsed = parseInputValue(raw, resolvedLocale);
    if (raw.trim() === "") {
      setInputError(null);
      onChange(null);
      return;
    }
    if (!parsed) {
      setInputError(`Enter a valid date in ${fmt} format.`);
      return;
    }
    setInputError(null);
    onChange(parsed);
    setDisplayMonth(startOfMonth(parsed));
  }

  function handleInputBlur(): void {
    if (inputValue.trim() === "") {
      setInputError(null);
      return;
    }
    const parsed = parseInputValue(inputValue, resolvedLocale);
    if (!parsed) {
      setInputError(
        `Enter a valid date in ${getDateFormat(resolvedLocale)} format.`,
      );
    }
  }

  // ---------------------------------------------------------------------------
  // Grid keyboard handler
  // ---------------------------------------------------------------------------

  function handleGridKeyDown(e: KeyboardEvent<HTMLElement>): void {
    const key = e.key;
    if (
      key !== "ArrowLeft" &&
      key !== "ArrowRight" &&
      key !== "ArrowUp" &&
      key !== "ArrowDown" &&
      key !== "Home" &&
      key !== "End" &&
      key !== "PageUp" &&
      key !== "PageDown" &&
      key !== "Enter" &&
      key !== " " &&
      key !== "Escape"
    ) {
      return;
    }

    e.preventDefault();

    if (key === "Escape") {
      close();
      return;
    }

    let next = focusedDate;
    let newMonth = displayMonth;

    switch (key) {
      case "ArrowRight":
        next = addDays(focusedDate, 1);
        break;
      case "ArrowLeft":
        next = addDays(focusedDate, -1);
        break;
      case "ArrowDown":
        next = addDays(focusedDate, 7);
        break;
      case "ArrowUp":
        next = addDays(focusedDate, -7);
        break;
      case "Home":
        next = startOfMonth(displayMonth);
        break;
      case "End":
        next = endOfMonth(displayMonth);
        break;
      case "PageUp":
        newMonth = addMonths(displayMonth, -1);
        next = clampToMonth(
          new Date(
            newMonth.getFullYear(),
            newMonth.getMonth(),
            focusedDate.getDate(),
          ),
          newMonth,
        );
        break;
      case "PageDown":
        newMonth = addMonths(displayMonth, 1);
        next = clampToMonth(
          new Date(
            newMonth.getFullYear(),
            newMonth.getMonth(),
            focusedDate.getDate(),
          ),
          newMonth,
        );
        break;
      case "Enter":
      case " ":
        if (!isCellDisabled(focusedDate)) {
          onChange(focusedDate);
          setInputValue(formatDateForInput(focusedDate, resolvedLocale));
          setInputError(null);
          close();
        }
        return;
    }

    // Cross-month navigation: update displayMonth if needed
    if (
      next.getMonth() !== displayMonth.getMonth() ||
      next.getFullYear() !== displayMonth.getFullYear()
    ) {
      newMonth = startOfMonth(next);
    }

    setDisplayMonth(newMonth);
    setFocusedDate(next);
  }

  // Tab cycling within dialog: prev → next → close → (wrap)
  function handleDialogKeyDown(e: KeyboardEvent<HTMLDivElement>): void {
    if (e.key === "Escape") {
      e.preventDefault();
      close();
      return;
    }
    if (e.key !== "Tab") return;

    // Only handle Tab if focus is on one of the three nav/close buttons
    const focused = document.activeElement;
    const dialogEl = dialogRef.current;
    if (!dialogEl) return;

    const tabbable = Array.from(
      dialogEl.querySelectorAll<HTMLElement>(
        ".artui-dp-nav-btn, .artui-dp-close-btn",
      ),
    );
    if (tabbable.length === 0) return;

    const idx = tabbable.indexOf(focused as HTMLElement);
    if (idx === -1) return; // focus is on a day cell; let Tab exit the grid normally

    e.preventDefault();
    if (e.shiftKey) {
      const prevIdx = (idx - 1 + tabbable.length) % tabbable.length;
      tabbable[prevIdx]?.focus();
    } else {
      const nextIdx = (idx + 1) % tabbable.length;
      tabbable[nextIdx]?.focus();
    }
  }

  // ---------------------------------------------------------------------------
  // Derive label wiring
  // ---------------------------------------------------------------------------

  const {
    label,
    "aria-label": ariaLabel,
    "aria-labelledby": ariaLabelledBy,
  } = labelRest as {
    label?: string;
    "aria-label"?: string;
    "aria-labelledby"?: string;
  };

  const inputAriaLabel = label ? undefined : ariaLabel;
  const inputAriaLabelledBy = label ? undefined : ariaLabelledBy;

  // ---------------------------------------------------------------------------
  // Render
  // ---------------------------------------------------------------------------

  injectStyle();

  const today = new Date();

  const activeError = inputError ?? externalError ?? null;

  const element = (
    <div className="artui-datepicker">
      {label && (
        <label htmlFor={inputId} className="artui-dp-label">
          {label}
        </label>
      )}

      <div className="artui-dp-input-row">
        <input
          id={inputId}
          type="text"
          className="artui-dp-input"
          value={inputValue}
          placeholder={getDateFormat(resolvedLocale)}
          aria-label={inputAriaLabel}
          aria-labelledby={inputAriaLabelledBy}
          aria-describedby={errorId}
          aria-required={required || undefined}
          aria-invalid={activeError ? "true" : undefined}
          onChange={(e) => handleInputChange(e.target.value)}
          onBlur={handleInputBlur}
        />
        <button
          ref={triggerRef}
          type="button"
          className="artui-dp-trigger"
          aria-haspopup="dialog"
          aria-expanded={isOpen}
          aria-label="Open date picker"
          onClick={() => (isOpen ? close() : open())}
          onKeyDown={(e) => {
            if (e.key === "Enter" || e.key === " ") {
              e.preventDefault();
              isOpen ? close() : open();
            }
          }}
        >
          {/* Calendar icon using a Unicode character — consumers can replace via CSS */}
          <span aria-hidden="true">&#x1F4C5;</span>
        </button>
      </div>

      <span
        id={errorId}
        className="artui-dp-error"
        role={activeError ? "alert" : undefined}
      >
        {activeError ?? ""}
      </span>

      {/* Always-present live region for screen reader month announcements */}
      <div
        id={liveRegionId}
        aria-live="polite"
        aria-atomic="true"
        className="artui-dp-sr-only"
      >
        {liveText}
      </div>

      {isOpen && (
        <div
          ref={dialogRef}
          role="dialog"
          aria-modal="true"
          aria-labelledby={headingId}
          className="artui-dp-dialog"
          onKeyDown={handleDialogKeyDown}
        >
          <div className="artui-dp-dialog-header">
            <button
              type="button"
              className="artui-dp-nav-btn"
              aria-label={prevMonthLabel}
              onClick={() => {
                const prev = addMonths(displayMonth, -1);
                setDisplayMonth(prev);
                setFocusedDate(clampToMonth(focusedDate, prev));
              }}
            >
              <span aria-hidden="true">&#x2039;</span>
            </button>

            <h2 id={headingId} className="artui-dp-heading">
              {headingText}
            </h2>

            <button
              type="button"
              className="artui-dp-nav-btn"
              aria-label={nextMonthLabel}
              onClick={() => {
                const next = addMonths(displayMonth, 1);
                setDisplayMonth(next);
                setFocusedDate(clampToMonth(focusedDate, next));
              }}
            >
              <span aria-hidden="true">&#x203A;</span>
            </button>

            <button
              type="button"
              className="artui-dp-close-btn"
              aria-label="Close"
              onClick={close}
            >
              <span aria-hidden="true">&#x2715;</span>
            </button>
          </div>

          <table role="grid" aria-label={headingText} className="artui-dp-grid">
            <thead>
              <tr role="row">
                {weekdayHeaders.map((h) => (
                  <th
                    key={h.long}
                    role="columnheader"
                    abbr={h.long}
                    scope="col"
                  >
                    {h.short}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody>
              {calendarGrid.map((week, wi) => (
                <tr key={wi} role="row">
                  {week.map((date, di) => {
                    if (!date) {
                      return (
                        <td
                          key={di}
                          role="gridcell"
                          className="artui-dp-empty-cell"
                        />
                      );
                    }
                    const isSelected = value ? isSameDay(date, value) : false;
                    const isToday = isSameDay(date, today);
                    const isDisabled = isCellDisabled(date);
                    const isFocused = isSameDay(date, focusedDate);

                    return (
                      <td
                        key={di}
                        role="gridcell"
                        className="artui-dp-day-cell"
                      >
                        <button
                          type="button"
                          className="artui-dp-day-btn"
                          tabIndex={isFocused ? 0 : -1}
                          data-focused-day={isFocused ? "true" : undefined}
                          aria-selected={isSelected ? "true" : "false"}
                          aria-current={isToday ? "date" : undefined}
                          aria-disabled={isDisabled ? "true" : undefined}
                          aria-label={new Intl.DateTimeFormat(resolvedLocale, {
                            day: "numeric",
                            month: "long",
                            year: "numeric",
                          }).format(date)}
                          disabled={isDisabled}
                          onKeyDown={handleGridKeyDown}
                          onClick={() => {
                            if (!isDisabled) {
                              onChange(date);
                              setInputValue(
                                formatDateForInput(date, resolvedLocale),
                              );
                              setInputError(null);
                              close();
                            }
                          }}
                          onFocus={() => setFocusedDate(date)}
                        >
                          {date.getDate()}
                        </button>
                      </td>
                    );
                  })}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );

  if (runtimeViolation) {
    return withErrorOverlay(element, {
      key: runtimeViolation.key,
      component: "Datepicker",
      wcag: runtimeViolation.wcag,
      message: runtimeViolation.message,
    });
  }

  return element;
}

import type { ReactElement } from "react";

const isDev =
  typeof process !== "undefined" && process.env.NODE_ENV !== "production";

const reported = new Set<string>();

interface DevOverlayOptions {
  /** Stable key for de-duplicating the console.error call. */
  key: string;
  /** Component name shown in the error prefix, e.g. "Image". */
  component: string;
  /** Optional WCAG criterion, e.g. "1.1.1". */
  wcag?: string;
  /** Human-readable description of what went wrong. */
  message: string;
}

/**
 * Wraps `element` in a red full-coverage overlay and emits a console.error.
 *
 * No-op in production. In development, logs once per `key` then returns the
 * element wrapped in a positioned <span> with a red overlay on top.
 * The overlay uses aria-hidden and pointerEvents:none so it does not affect
 * the accessibility tree or interaction.
 */
export function withErrorOverlay(
  element: ReactElement,
  { key, component, wcag, message }: DevOverlayOptions,
): ReactElement {
  if (!isDev) return element;

  if (!reported.has(key)) {
    reported.add(key);
    const wcagSuffix = wcag ? ` [WCAG ${wcag}]` : "";
    console.error(`[artui] <${component}>${wcagSuffix}: ${message}`);
  }

  return (
    <span style={{ position: "relative", display: "inline-block" }}>
      {element}
      <span
        aria-hidden="true"
        style={{
          position: "absolute",
          inset: 0,
          background: "#d62828",
          pointerEvents: "none",
        }}
      />
    </span>
  );
}

/** Reset the de-duplication cache. Test-only. */
export function __resetDevOverlayCache(): void {
  reported.clear();
}

import { type ImgHTMLAttributes, useMemo } from 'react';

import { withErrorOverlay } from '../../lib/dev-overlay';

const FORBIDDEN_ALTS = ['', 'img', 'image', 'photo', 'picture', 'icon'] as const;
type ForbiddenAlt = (typeof FORBIDDEN_ALTS)[number];

type SafeAlt<T extends string> =
  Lowercase<T> extends ForbiddenAlt
    ? `'${T}' is not meaningful alt text. Describe what the image shows`
    : T;

type BaseImgProps = Omit<ImgHTMLAttributes<HTMLImageElement>, 'alt' | 'role'>;

type DecorativeProps = BaseImgProps & {
  decorative: true;
  alt?: never;
};

type AccessibleProps<T extends string> = BaseImgProps & {
  decorative?: false;
  alt: SafeAlt<T>;
};

export type ImageProps<T extends string> = DecorativeProps | AccessibleProps<T>;

export function Image<const T extends string>(props: ImageProps<T>) {
  const { decorative, alt, style, loading, ...rest } = props as
    | (DecorativeProps & { alt?: undefined })
    | (AccessibleProps<string> & { decorative?: false });

  const runtimeError = useMemo(() => {
    if (decorative) return null;
    const value = typeof alt === 'string' ? alt.trim() : '';
    if (value === '') {
      return 'Alt text is empty or contains only whitespace.';
    }
    if ((FORBIDDEN_ALTS as readonly string[]).includes(value.toLowerCase())) {
      return `'${alt}' is not meaningful alt text. Describe what the image shows.`;
    }
    return null;
  }, [decorative, alt]);

  if (decorative) {
    return <img {...rest} alt="" role="presentation" loading={loading ?? 'lazy'} style={style} />;
  }

  const img = <img {...rest} alt={alt as string} loading={loading ?? 'lazy'} style={style} />;

  if (!runtimeError) return img;

  return withErrorOverlay(img, {
    key: `Image:placeholder-alt:${String(alt)}`,
    component: 'Image',
    wcag: '1.1.1',
    message: runtimeError,
  });
}

